new_desc = {
    366: 'Из гаража в Купертино — до самой дорогой компании в истории. История дизайна, упрямства и человека, который дважды спас то что сам чуть не уничтожил.',
    367: 'От продажи кроссовок из багажника до самого узнаваемого спортивного бренда планеты. История о галочке за $35 и слогане придуманном перед казнью.',
    368: 'Напиток придуманный аптекарем как лекарство — стал самым продаваемым безалкогольным в истории. 140 лет, 2 миллиарда порций в день.',
    369: 'Братья открыли закусочную — коммивояжёр угнал их мечту и построил крупнейшую сеть мира. История о франшизе, недвижимости и картошке фри.',
    370: '17-летний швед начал торговать спичками и построил крупнейшую мебельную империю мира. История о плоских упаковках и самом хитром бизнесе XX века.',
    372: 'Из торговли сушёной рыбой — до крупнейшего технологического конгломерата Азии. Как одна корейская семья построила государство внутри государства.',
}

for book in data:
    if book['id'] in new_desc:
        book['description'] = new_desc[book['id']]

